input.command:
$jsonl = "c:\webproject\Webnu\Webnu\.cursor\conversations\2502c06f-historial-webnu.jsonl"
$lines = Get-Content $jsonl -Encoding UTF8
$out = @()
$out += "# Historial de conversación Cursor — Webnu"
$out += ""
$out += "**ID:** 2502c06f-0e81-4866-a184-aacb72fa4ba5"
$out += "**Workspace original:** c:\webproject\Webnu"
$out += "**Importado:** $(Get-Date -Format 'yyyy-MM-dd HH:mm')"
$out += ""
$msgNum = 0
foreach ($line in $lines) {
  if ([string]::IsNullOrWhiteSpace($line)) { continue }
  try { $obj = $line | ConvertFrom-Json } catch { continue }
  $role = $obj.role
  $content = $obj.message.content
  $texts = @()
  foreach ($part in $content) {
    if ($part.type -eq 'text' -and $part.text) {
      $t = $part.text -replace '<user_query>\s*','' -replace '\s*</user_query>',''
      if ($t -match '^\[REDACTED\]$') { continue }
      if ($t.Length -gt 0) { $texts += $t }
    }
  }
  if ($texts.Count -eq 0) { continue }
  $msgNum++
  $label = if ($role -eq 'user') { 'Usuario' } else { 'Cursor' }
  $out += "---"
  $out += ""
  $out += "## $msgNum. $label"
  $out += ""
  $out += ($texts -join "`n`n")
  $out += ""
}
$mdPath = "c:\webproject\Webnu\Webnu\docs\HISTORIAL-CURSOR-WEBNU.md"
New-Item -ItemType Directory -Force -Path (Split-Path $mdPath) | Out-Null
$out -join "`n" | Set-Content $mdPath -Encoding UTF8
Write-Host "Mensajes exportados: $msgNum"
Write-Host "Archivo: $mdPath"

