var wnDropzonePreview =
  '<div class="dz-preview wn-dz-preview">' +
  '<div class="dz-image"><img data-dz-thumbnail alt="" /></div>' +
  '<div class="dz-details">' +
  '<span class="dz-filename" data-dz-name></span>' +
  '<span class="dz-size" data-dz-size></span>' +
  '</div>' +
  '<div class="dz-progress"><span class="dz-upload" data-dz-uploadprogress></span></div>' +
  '<div class="dz-error-message"><span data-dz-errormessage></span></div>' +
  '</div>';

function hideDropzoneMessage(dz) {
  if (!dz || !dz.element) {
    return;
  }
  dz.element.classList.add('dz-started');
  var msg = dz.element.querySelector('.dz-message');
  if (msg) {
    msg.style.display = 'none';
  }
}

function removePreviewNode(file) {
  if (file.previewElement && file.previewElement.parentNode) {
    file.previewElement.parentNode.removeChild(file.previewElement);
  }
}

function addMockFile(dz, url, name) {
  if (!url) {
    return;
  }
  var mock = { name: name, size: 2000, accepted: true, status: Dropzone.SUCCESS };
  mock._wnPersisted = true;
  dz.emit('addedfile', mock);
  dz.emit('thumbnail', mock, url);
  dz.emit('complete', mock);
  dz.files.push(mock);
  hideDropzoneMessage(dz);
}

function bindExplicitRemove(dz, el) {
  el.addEventListener('click', function (e) {
    if (!e.target.closest('[data-dz-remove]')) {
      return;
    }
    dz.files.forEach(function (file) {
      file._wnUserRemoved = true;
    });
  });
}

function handleRemovedFile(dz, el, file) {
  removePreviewNode(file);
  if (!file._wnUserRemoved) {
    return;
  }
  $.ajax({
    headers: { 'X-CSRF-TOKEN': cfg.csrf },
    type: 'DELETE',
    url: el.dataset.deleteUrl,
  }).always(function () {
    var msg = el.querySelector('.dz-message');
    if (msg) {
      msg.style.display = '';
    }
    el.classList.remove('dz-started');
    refreshPreview();
  });
}

function buildDropzoneOptions(el, opts) {
  return {
    url: el.dataset.uploadUrl,
    paramName: opts.paramName,
    maxFiles: 1,
    maxFilesize: 5,
    acceptedFiles: 'image/*',
    addRemoveLinks: true,
    dictRemoveFile: 'Quitar',
    thumbnailWidth: 160,
    thumbnailHeight: 160,
    previewTemplate: wnDropzonePreview,
    headers: { 'X-CSRF-TOKEN': cfg.csrf },
    init: function () {
      var dz = this;
      bindExplicitRemove(dz, el);
      addMockFile(dz, opts.existingUrl, opts.fileLabel);

      dz.on('addedfile', function (file) {
        hideDropzoneMessage(dz);
        if (dz.files.length > 1) {
          var previous = dz.files[0] === file ? dz.files[1] : dz.files[0];
          if (previous) {
            previous._wnUserRemoved = false;
            dz.removeFile(previous);
          }
        }
      });

      dz.on('success', function (file, response) {
        file._wnPersisted = true;
        if (response && response.url) {
          opts.onUrl(response.url);
        }
        refreshPreview();
      });

      dz.on('error', function (_file, message) {
        window.alert(typeof message === 'string' ? message : opts.errorText);
      });
    },
    removedfile: function (file) {
      handleRemovedFile(this, el, file);
    },
  };
}

