var wnDropzonePreview =
  '<div class="dz-preview wn-dz-preview">' +
  '<div class="dz-image"><img data-dz-thumbnail alt="" /></div>' +
  '<div class="dz-details">' +
  '<span class="dz-filename" data-dz-name></span>' +
  '<span class="dz-size" data-dz-size></span>' +
  '</div>' +
  '<div class="dz-progress"><span class="dz-upload" data-dz-uploadprogress></span></div>' +
  '<div class="dz-error-message"><span data-dz-errormessage></span></div>' +
  '</div>';

function hideDropzoneMessage(dz) {
  if (!dz || !dz.element) {
    return;
  }
  dz.element.classList.add('dz-started');
  var msg = dz.element.querySelector('.dz-message');
  if (msg) {
    msg.style.display = 'none';
  }
}

function removePreviewNode(file) {
  if (file.previewElement && file.previewElement.parentNode) {
    file.previewElement.parentNode.removeChild(file.previewElement);
  }
}

function addMockFile(dz, url, name) {
  if (!url) {
    return;
  }
  var mock = { name: name, size: 2000, accepted: true, status: 'success' };
  mock._wnPersisted = true;
  dz.emit('addedfile', mock);
  dz.emit('thumbnail', mock, url);
  dz.emit('complete', mock);
  dz.files.push(mock);
  hideDropzoneMessage(dz);
}

function bindExplicitRemove(dz, el) {
  el.addEventListener('click', function (e) {
    if (!e.target.closest('[data-dz-remove]')) {
      return;
    }
    dz.files.forEach(function (file) {
      file._wnUserRemoved = true;
    });
  });
}

function handleRemovedFile(dz, el, file) {
  removePreviewNode(file);
  if (!file._wnUserRemoved) {
    return;
  }
  $.ajax({
    headers: { 'X-CSRF-TOKEN': cfg.csrf },
    type: 'DELETE',
    url: el.dataset.deleteUrl,
  }).always(function () {
    var msg = el.querySelector('.dz-message');
    if (msg) {
      msg.style.display = '';
    }
    el.classList.remove('dz-started');
    refreshPreview();
  });
}

function buildDropzoneOptions(el, opts) {
  return {
    url: el.dataset.uploadUrl,
    paramName: opts.paramName,
    maxFiles: 1,
    maxFilesize: 5,
    acceptedFiles: 'image/*',
    addRemoveLinks: true,
    dictRemoveFile: 'Quitar',
    thumbnailWidth: 160,
    thumbnailHeight: 160,
    previewTemplate: wnDropzonePreview,
    headers: { 'X-CSRF-TOKEN': cfg.csrf },
    init: function () {
      var dz = this;
      bindExplicitRemove(dz, el);
      addMockFile(dz, opts.existingUrl, opts.fileLabel);

      dz.on('addedfile', function (file) {
        hideDropzoneMessage(dz);
        if (dz.files.length > 1) {
          var previous = dz.files[0] === file ? dz.files[1] : dz.files[0];
          if (previous) {
            previous._wnUserRemoved = false;
            dz.removeFile(previous);
          }
        }
      });

      dz.on('success', function (file, response) {
        file._wnPersisted = true;
        if (response && response.url) {
          opts.onUrl(response.url);
        }
        refreshPreview();
      });

      dz.on('error', function (_file, message) {
        window.alert(typeof message === 'string' ? message : opts.errorText);
      });
    },
    removedfile: function (file) {
      handleRemovedFile(this, el, file);
    },
  };
}

function createDropzone(el, options) {
  if (!el || el.dropzone) {
    return el && el.dropzone ? el.dropzone : null;
  }
  return new Dropzone(el, options);
}

function initFallbackUpload(el, existingUrl) {
  if (!el || el.dataset.fallbackBound === '1') {
    return;
  }
  el.dataset.fallbackBound = '1';

  var input = document.createElement('input');
  input.type = 'file';
  input.accept = 'image/*';
  input.className = 'visually-hidden';
  input.setAttribute('aria-hidden', 'true');
  input.tabIndex = -1;
  el.appendChild(input);

  function showPreview(url) {
    var preview = el.querySelector('.wn-fallback-preview');
    if (!preview) {
      preview = document.createElement('div');
      preview.className = 'wn-fallback-preview text-center p-2';
      el.appendChild(preview);
    }
    var msg = el.querySelector('.wn-dropzone-message');
    if (msg) {
      msg.classList.add('d-none');
    }
    preview.innerHTML =
      '<img src="' +
      url +
      '" alt="" class="img-fluid rounded mb-2" style="max-height:120px">' +
      '<button type="button" class="btn btn-sm btn-outline-danger wn-fallback-remove">Quitar</button>';
  }

  if (existingUrl) {
    showPreview(existingUrl);
  }

  el.addEventListener('click', function (e) {
    if (e.target.closest('.wn-fallback-remove')) {
      return;
    }
    input.click();
  });

  el.addEventListener('click', function (e) {
    if (!e.target.closest('.wn-fallback-remove')) {
      return;
    }
    e.preventDefault();
    e.stopPropagation();
    $.ajax({
      headers: { 'X-CSRF-TOKEN': cfg.csrf },
      type: 'DELETE',
      url: el.dataset.deleteUrl,
    }).always(function () {
      var preview = el.querySelector('.wn-fallback-preview');
      if (preview) {
        preview.remove();
      }
      var msg = el.querySelector('.wn-dropzone-message');
      if (msg) {
        msg.classList.remove('d-none');
      }
      input.value = '';
      refreshPreview();
    });
  });

  input.addEventListener('change', function () {
    if (!input.files || !input.files[0]) {
      return;
    }
    var fd = new FormData();
    fd.append(el.dataset.param, input.files[0]);
    el.classList.add('is-uploading');
    fetch(el.dataset.uploadUrl, {
      method: 'POST',
      headers: {
        'X-CSRF-TOKEN': cfg.csrf,
        Accept: 'application/json',
        'X-Requested-With': 'XMLHttpRequest',
      },
      body: fd,
    })
      .then(function (res) {
        if (!res.ok) {
          throw new Error('upload failed');
        }
        return res.json();
      })
      .then(function (data) {
        if (data.url) {
          showPreview(data.url);
        }
        refreshPreview();
      })
      .catch(function () {
        window.alert('No se pudo subir la imagen. Comprueba el formato (JPG, PNG…) y que pese menos de 5 MB.');
      })
      .finally(function () {
        el.classList.remove('is-uploading');
        input.value = '';
      });
  });
}

function initDropzones() {
  var logoEl = document.getElementById('wn-dropzone-logo');
  var headerEl = document.getElementById('wn-dropzone-header');

  if (typeof Dropzone === 'undefined') {
    initFallbackUpload(logoEl, cfg.logoUrl);
    initFallbackUpload(headerEl, cfg.headerUrl);
    return;
  }

  Dropzone.autoDiscover = false;

  try {
    createDropzone(
      logoEl,
      buildDropzoneOptions(logoEl, {
        paramName: 'logo',
        fileLabel: 'logo',
        existingUrl: cfg.logoUrl,
        errorText: 'No se pudo subir el logo.',
        onUrl: function (url) {
          cfg.logoUrl = url;
        },
      })
    );

    createDropzone(
      headerEl,
      buildDropzoneOptions(headerEl, {
        paramName: 'header',
        fileLabel: 'header',
        existingUrl: cfg.headerUrl,
        errorText: 'No se pudo subir la imagen de cabecera.',
        onUrl: function (url) {
          cfg.headerUrl = url;
        },
      })
    );
  } catch (err) {
    initFallbackUpload(logoEl, cfg.logoUrl);
    initFallbackUpload(headerEl, cfg.headerUrl);
  }
}

