/**
 * @return array<string, string>
 */
protected function authHeaders(string $apiKey): array
{
    return ['x-goog-api-key' => $apiKey];
}

protected function failedFromException(GuzzleException $e): MenuScanResult
{
    [$message, $code] = $this->parseApiError($e);

    return MenuScanResult::failed($message, $this->name(), $code);
}

/**
 * @return array{0: string, 1: string|null}
 */
protected function parseApiError(GuzzleException $e): array
{
    if ($e instanceof ClientException && $e->hasResponse()) {
        $status = $e->getResponse()->getStatusCode();
        $body = json_decode((string) $e->getResponse()->getBody(), true);
        $apiMessage = is_array($body) ? ($body['error']['message'] ?? null) : null;

        if ($status === 429) {
            return [
                'La cuota de Gemini está agotada o hay demasiadas peticiones. Espera unos minutos, revisa tu plan en Google AI Studio, o cambia el modelo en Plataforma → Escaneo IA (prueba gemini-1.5-flash o gemini-2.0-flash-lite).',
                'quota_exceeded',
            ];
        }
        if ($status === 403) {
            return [
                'La API key de Gemini no tiene permiso para este modelo. Revisa la clave en Plataforma → Escaneo IA.',
                'auth_error',
            ];
        }
        if ($status === 400 && $apiMessage) {
            return [
                'Petición rechazada por Gemini: ' . $this->sanitizeForLog($apiMessage),
                'bad_request',
            ];
        }
    }

    return [
        'No se pudo conectar con Gemini. Comprueba la API key y tu conexión.',
        null,
    ];
}

protected function sanitizeForLog(string $text): string
{
    return (string) preg_replace('/AIza[a-zA-Z0-9_-]{20,}/', '[API_KEY]', $text);
}

