/* Pantalla de espera — análisis IA */
.wn-scan-processing {
    position: fixed;
    inset: 0;
    z-index: 1090;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 1.5rem;
    overflow: hidden;
}

.wn-scan-processing[hidden] {
    display: none !important;
}

.wn-scan-processing__backdrop {
    position: absolute;
    inset: 0;
    background:
        radial-gradient(ellipse 80% 60% at 50% 0%, rgba(0, 116, 217, 0.35) 0%, transparent 55%),
        radial-gradient(ellipse 60% 50% at 80% 100%, rgba(99, 102, 241, 0.25) 0%, transparent 50%),
        linear-gradient(165deg, #020818 0%, #061228 40%, #0a1f3d 100%);
}

.wn-scan-processing__grid {
    position: absolute;
    inset: -50%;
    background-image:
        linear-gradient(rgba(0, 180, 255, 0.06) 1px, transparent 1px),
        linear-gradient(90deg, rgba(0, 180, 255, 0.06) 1px, transparent 1px);
    background-size: 48px 48px;
    animation: wn-scan-grid-drift 20s linear infinite;
    mask-image: radial-gradient(ellipse 70% 60% at 50% 45%, #000 20%, transparent 75%);
}

@keyframes wn-scan-grid-drift {
    0% { transform: translate(0, 0) rotate(0deg); }
    100% { transform: translate(48px, 48px) rotate(0deg); }
}

.wn-scan-processing__content {
    position: relative;
    z-index: 2;
    width: min(100%, 420px);
    text-align: center;
    color: #e8f4ff;
}

.wn-scan-processing__scanner {
    position: relative;
    width: 140px;
    height: 140px;
    margin: 0 auto 1.75rem;
}

.wn-scan-processing__ring {
    position: absolute;
    inset: 0;
    border-radius: 50%;
    border: 2px solid transparent;
}

.wn-scan-processing__ring--1 {
    border-top-color: #00b4ff;
    border-right-color: rgba(0, 180, 255, 0.3);
    animation: wn-scan-spin 2.4s linear infinite;
}

.wn-scan-processing__ring--2 {
    inset: 12px;
    border-bottom-color: #6366f1;
    border-left-color: rgba(99, 102, 241, 0.35);
    animation: wn-scan-spin 1.6s linear infinite reverse;
}

.wn-scan-processing__core {
    position: absolute;
    inset: 28px;
    border-radius: 50%;
    background: linear-gradient(145deg, rgba(0, 116, 217, 0.5), rgba(99, 102, 241, 0.45));
    box-shadow:
        0 0 40px rgba(0, 180, 255, 0.45),
        inset 0 0 24px rgba(255, 255, 255, 0.12);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 2rem;
    color: #fff;
    animation: wn-scan-pulse 2s ease-in-out infinite;
}

.wn-scan-processing__beam {
    position: absolute;
    left: 50%;
    top: 50%;
    width: 200%;
    height: 3px;
    margin-top: -1.5px;
    margin-left: -100%;
    background: linear-gradient(90deg, transparent, rgba(0, 220, 255, 0.9), transparent);
    animation: wn-scan-beam 2.8s ease-in-out infinite;
    transform-origin: center;
}

@keyframes wn-scan-spin {
    to { transform: rotate(360deg); }
}

@keyframes wn-scan-pulse {
    0%, 100% { transform: scale(1); opacity: 1; }
    50% { transform: scale(1.04); opacity: 0.92; }
}

@keyframes wn-scan-beam {
    0% { transform: rotate(0deg); opacity: 0.3; }
    50% { opacity: 1; }
    100% { transform: rotate(180deg); opacity: 0.3; }
}

.wn-scan-processing__eyebrow {
    font-size: 0.6875rem;
    font-weight: 700;
    letter-spacing: 0.14em;
    text-transform: uppercase;
    color: rgba(0, 200, 255, 0.85);
    margin-bottom: 0.35rem;
}

.wn-scan-processing__title {
    font-size: 1.5rem;
    font-weight: 700;
    margin: 0 0 0.75rem;
    color: #fff;
    text-shadow: 0 0 30px rgba(0, 180, 255, 0.35);
}

.wn-scan-processing__status {
    font-size: 0.9375rem;
    color: rgba(232, 244, 255, 0.9);
    min-height: 1.5em;
    margin-bottom: 1.25rem;
    transition: opacity 0.25s;
}

.wn-scan-processing__status.is-fading {
    opacity: 0.4;
}

.wn-scan-processing__progress {
    height: 4px;
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.12);
    overflow: hidden;
    margin-bottom: 1.5rem;
}

.wn-scan-processing__progress-bar {
    height: 100%;
