    box-shadow: 0 0 12px rgba(0, 212, 255, 0.6);
}

@keyframes wn-scan-progress {
    0% { width: 8%; }
    25% { width: 35%; }
    50% { width: 58%; }
    75% { width: 78%; }
    92% { width: 88%; }
    100% { width: 92%; }
}

@keyframes wn-scan-shimmer {
    0% { background-position: 100% 0; }
    100% { background-position: -100% 0; }
}

.wn-scan-processing__steps {
    list-style: none;
    padding: 0;
    margin: 0 0 1rem;
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
