                        <MotionDiv className="wn-split__text" variants={fadeUp}>
                            <h3>{content.success.blocks[1].title}</h3>
                            <p>{content.success.blocks[1].text}</p>
                        </MotionDiv>
                    </motion.div>
                </div>
            </MotionSection>

            {/* IA */}
            <MotionSection id="ia" className="wn-section wn-section--ia" {...useInViewOnce()}>
                <motion.div
                    className="wn-ia-card"
                    variants={scaleIn}
                    initial="hidden"
                    whileInView="visible"
