                                animate={{ rotateY: [-6, -4, -6] }}
                                transition={{ duration: 6, repeat: Infinity, ease: 'easeInOut' }}
                            >
                                <div className="wn-tvpik-tv__screen">
                                    <img src={content.tvpik.dishImage} alt="Plato en pantalla" />
