import React, { useEffect, useRef, useState } from 'react';
import { motion } from 'framer-motion';

/** Framer Motion 4 no incluye whileInView; usamos Intersection Observer. */
export function useReveal({ threshold = 0.12, once = true } = {}) {
    const ref = useRef(null);
    const [visible, setVisible] = useState(false);

    useEffect(() => {
        const node = ref.current;
        if (!node) {
            return undefined;
        }

        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting) {
                    setVisible(true);
                    if (once) {
                        observer.disconnect();
                    }
                } else if (!once) {
                    setVisible(false);
                }
            },
            { threshold }
        );

        observer.observe(node);
        return () => observer.disconnect();
    }, [threshold, once]);

    return {
        ref,
        visible,
        initial: 'hidden',
        animate: visible ? 'visible' : 'hidden',
    };
}

export function Reveal({ as: Component = motion.div, children, variants, className, threshold, once, ...rest }) {
    const reveal = useReveal({ threshold, once });

    return (
        <Component
            ref={reveal.ref}
            className={className}
            variants={variants}
            initial={reveal.initial}
            animate={reveal.animate}
            {...rest}
        >
            {children}
        </Component>
    );
}

