(function () {
    const headline = document.getElementById('hero-headline');
    if (headline) {
        const hooks = JSON.parse(headline.dataset.hooks || '[]');
        let index = 0;
        if (hooks.length > 1) {
            setInterval(function () {
                headline.classList.add('is-fading');
                setTimeout(function () {
                    index = (index + 1) % hooks.length;
                    headline.textContent = hooks[index];
                    headline.classList.remove('is-fading');
                }, 450);
            }, 5200);
        }
    }

    window.toggleFAQ = function (btn) {
        const item = btn.closest('.faq-item');
        if (!item) return;
        const open = item.classList.contains('faq-open');
        document.querySelectorAll('.faq-item').forEach(function (el) {
            el.classList.remove('faq-open');
        });
        if (!open) {
            item.classList.add('faq-open');
        }
    };

    const tplTrack = document.getElementById('tpl-track');
    if (tplTrack) {
        const scrollStep = function (dir) {
            const slide = tplTrack.querySelector('.landing-tpl-slide');
            const gap = 12;
            const amount = slide ? slide.offsetWidth + gap : 152;
            tplTrack.scrollBy({ left: dir * amount, behavior: 'smooth' });
        };
        document.querySelectorAll('[data-tpl-prev]').forEach(function (btn) {
            btn.addEventListener('click', function () { scrollStep(-1); });
        });
        document.querySelectorAll('[data-tpl-next]').forEach(function (btn) {
            btn.addEventListener('click', function () { scrollStep(1); });
        });
    }

    window.addEventListener('scroll', function () {
        const nav = document.querySelector('[data-landing-nav]');
        if (!nav) return;
        if (window.scrollY > 20) {
            nav.classList.add('shadow-md');
        } else {
            nav.classList.remove('shadow-md');
        }
    });
})();

